import heapq
from typing import List


class Solution:
    def countFailedCharging(self, n: int, cars: List[List[int]]) -> int:
        events = []
        for i, (at, _ct, _wt) in enumerate(cars):
            heapq.heappush(events, (at, 1, "A", i))  # 到达事件，同刻优先级 1

        piles = [0] * n
        heapq.heapify(piles)  # 桩空闲时刻小根堆
        waiting = []
        failed = 0

        while events:
            t = events[0][0]
            batch = []
            while events and events[0][0] == t:
                batch.append(heapq.heappop(events))
            batch.sort(key=lambda x: x[1])  # 先处理释放(0)再到达(1)

            for _time, _pri, kind, data in batch:
                if kind == "F":
                    heapq.heappush(piles, t)  # 桩在 t 时刻可用
                else:
                    waiting.append(data)

            while piles and piles[0] <= t and waiting:
                car = waiting[0]
                at, ct, wt = cars[car]
                if t - at > wt:  # 等待超时，失败
                    waiting.pop(0)
                    failed += 1
                    continue
                heapq.heappop(piles)
                finish = t + ct
                heapq.heappush(events, (finish, 0, "F", 0))  # 充电结束释放
                waiting.pop(0)

        return failed
