using namespace std;

class Solution {
 public:
  int countFailedCharging(int n, vector<vector<int>>& cars) {
    using Event = tuple<int, int, char, int>;
    priority_queue<Event, vector<Event>, greater<Event>> events;
    for (int i = 0; i < (int)cars.size(); i++) {
      events.push({cars[i][0], 1, 'A', i});
    }

    priority_queue<int, vector<int>, greater<int>> piles;
    for (int i = 0; i < n; i++) piles.push(0);

    vector<int> waiting;
    int failed = 0;

    while (!events.empty()) {
      int t = get<0>(events.top());
      vector<Event> batch;
      while (!events.empty() && get<0>(events.top()) == t) {
        batch.push_back(events.top());
        events.pop();
      }
      sort(batch.begin(), batch.end(),
           [](const Event& a, const Event& b) { return get<1>(a) < get<1>(b); });

      for (auto& e : batch) {
        if (get<2>(e) == 'F')
          piles.push(t);
        else
          waiting.push_back(get<3>(e));
      }

      while (!piles.empty() && piles.top() <= t && !waiting.empty()) {
        int car = waiting[0];
        int at = cars[car][0], ct = cars[car][1], wt = cars[car][2];
        if (t - at > wt) {
          waiting.erase(waiting.begin());
          failed++;
          continue;
        }
        piles.pop();
        events.push({t + ct, 0, 'F', 0});
        waiting.erase(waiting.begin());
      }
    }
    return failed;
  }
};
