#include <stdlib.h>

/* --- 事件最小堆 (按 time 排序，time 相同时按 priority 排序) --- */
typedef struct { int time, pri, type, idx; } Evt;
typedef struct { Evt* a; int sz, cap; } EHeap;

static void epush(EHeap* h, int t, int p, int ty, int id) {
    if (h->sz == h->cap) {
        h->cap = h->cap ? h->cap * 2 : 64;
        h->a = (Evt*)realloc(h->a, h->cap * sizeof(Evt));
    }
    int i = h->sz++;
    while (i > 0) {
        int pi = (i - 1) / 2;
        if (h->a[pi].time < t) break;
        if (h->a[pi].time == t && h->a[pi].pri <= p) break;
        h->a[i] = h->a[pi]; i = pi;
    }
    h->a[i].time = t; h->a[i].pri = p; h->a[i].type = ty; h->a[i].idx = id;
}

static int eempty(EHeap* h) { return h->sz == 0; }
static int etop_t(EHeap* h) { return h->a[0].time; }

static void epop(EHeap* h, int* t, int* p, int* ty, int* id) {
    *t = h->a[0].time; *p = h->a[0].pri; *ty = h->a[0].type; *id = h->a[0].idx;
    h->a[0] = h->a[--h->sz];
    int i = 0;
    while (1) {
        int l = 2 * i + 1, r = 2 * i + 2, best = i;
        if (l < h->sz && (h->a[l].time < h->a[best].time ||
            (h->a[l].time == h->a[best].time && h->a[l].pri < h->a[best].pri))) best = l;
        if (r < h->sz && (h->a[r].time < h->a[best].time ||
            (h->a[r].time == h->a[best].time && h->a[r].pri < h->a[best].pri))) best = r;
        if (best == i) break;
        Evt tmp = h->a[i]; h->a[i] = h->a[best]; h->a[best] = tmp; i = best;
    }
}

/* --- 整数最小堆 (充电桩释放时间) --- */
typedef struct { int* a; int sz, cap; } IHeap;

static void ipush(IHeap* h, int v) {
    if (h->sz == h->cap) {
        h->cap = h->cap ? h->cap * 2 : 64;
        h->a = (int*)realloc(h->a, h->cap * sizeof(int));
    }
    int i = h->sz++;
    while (i > 0 && h->a[(i - 1) / 2] > v) { h->a[i] = h->a[(i - 1) / 2]; i = (i - 1) / 2; }
    h->a[i] = v;
}

static int itop(IHeap* h) { return h->sz > 0 ? h->a[0] : -1; }
static int iempty(IHeap* h) { return h->sz == 0; }

static void ipop(IHeap* h) {
    h->a[0] = h->a[--h->sz];
    int i = 0;
    while (1) {
        int l = 2 * i + 1, r = 2 * i + 2, best = i;
        if (l < h->sz && h->a[l] < h->a[best]) best = l;
        if (r < h->sz && h->a[r] < h->a[best]) best = r;
        if (best == i) break;
        int tmp = h->a[i]; h->a[i] = h->a[best]; h->a[best] = tmp; i = best;
    }
}

/* --- 主算法：事件驱动充电桩调度 --- */
int countFailedCharging(int n, int** cars, int carsSize) {
    EHeap ev = {NULL, 0, 0};
    for (int i = 0; i < carsSize; i++) epush(&ev, cars[i][0], 1, 1, i);

    IHeap pl = {NULL, 0, 0};
    for (int i = 0; i < n; i++) ipush(&pl, 0);

    int* wait = (int*)malloc(carsSize * sizeof(int));
    int wh = 0, wc = 0, failed = 0;

    while (!eempty(&ev)) {
        int ct = etop_t(&ev);

        Evt* batch = (Evt*)malloc(ev.sz * sizeof(Evt));
        int bsz = 0;
        while (!eempty(&ev) && etop_t(&ev) == ct) {
            int t, p, ty, id;
            epop(&ev, &t, &p, &ty, &id);
            batch[bsz].time = t; batch[bsz].pri = p; batch[bsz].type = ty; batch[bsz].idx = id;
            bsz++;
        }

        // 同时间先处理释放(pri=0)再处理到达(pri=1)
        for (int i = 0; i < bsz - 1; i++)
            for (int j = 0; j < bsz - 1 - i; j++)
                if (batch[j].pri > batch[j + 1].pri) {
                    Evt tmp = batch[j]; batch[j] = batch[j + 1]; batch[j + 1] = tmp;
                }

        for (int i = 0; i < bsz; i++) {
            if (batch[i].type == 0) ipush(&pl, ct);
            else wait[wc++] = batch[i].idx;
        }
        free(batch);

        // 分配可用充电桩给等待队列中的车辆(FCFS)
        while (!iempty(&pl) && itop(&pl) <= ct && wh < wc) {
            int car = wait[wh];
            int at = cars[car][0], carct = cars[car][1], wt = cars[car][2];
            if (ct - at > wt) { wh++; failed++; continue; }
            ipop(&pl);
            epush(&ev, ct + carct, 0, 0, 0);
            wh++;
        }
    }

    free(ev.a); free(pl.a); free(wait);
    return failed;
}
